package consumer

import (
	"encoding/json"
	"fmt"
	"log"
	"os"

	amqp "github.com/rabbitmq/amqp091-go"

	"notification-service/internal/handlers"
)

const (
	exchangeName = "notifications"
	queueName    = "notification-service.email"
	routingKey   = "email.*"
	prefetchCount = 10
)

type emailMessage struct {
	EventType string          `json:"event_type"`
	Timestamp string          `json:"timestamp"`
	Payload   json.RawMessage `json:"payload"`
}

func Start() error {
	conn, err := connect()
	if err != nil {
		return err
	}

	conn.NotifyClose(make(chan *amqp.Error, 1))

	ch, err := conn.Channel()
	if err != nil {
		return fmt.Errorf("open channel: %w", err)
	}

	if err := ch.Qos(prefetchCount, 0, false); err != nil {
		return fmt.Errorf("set prefetch: %w", err)
	}

	if err := ch.ExchangeDeclare(exchangeName, "topic", true, false, false, false, nil); err != nil {
		return fmt.Errorf("declare exchange: %w", err)
	}

	if _, err := ch.QueueDeclare(queueName, true, false, false, false, nil); err != nil {
		return fmt.Errorf("declare queue: %w", err)
	}

	if err := ch.QueueBind(queueName, routingKey, exchangeName, false, nil); err != nil {
		return fmt.Errorf("bind queue: %w", err)
	}

	msgs, err := ch.Consume(queueName, "", false, false, false, false, nil)
	if err != nil {
		return fmt.Errorf("start consume: %w", err)
	}

	log.Printf("[consumer] Listening on queue %q (routing: %s)", queueName, routingKey)

	connErrors := make(chan *amqp.Error, 1)
	conn.NotifyClose(connErrors)

	go func() {
		for msg := range msgs {
			processMessage(ch, msg)
		}
	}()

	if err := <-connErrors; err != nil {
		log.Printf("[consumer] Connection closed: %v", err)
		os.Exit(1)
	}

	return nil
}

func connect() (*amqp.Connection, error) {
	host := getenv("RABBITMQ_HOST", "rabbitmq")
	port := getenv("RABBITMQ_PORT", "5672")
	user := getenv("RABBITMQ_USER", "guest")
	pass := getenv("RABBITMQ_PASSWORD", "guest")
	vhost := getenv("RABBITMQ_VHOST", "/")

	url := fmt.Sprintf("amqp://%s:%s@%s:%s/%s", user, pass, host, port, vhost)
	log.Printf("[consumer] Connecting to RabbitMQ at %s:%s...", host, port)
	return amqp.Dial(url)
}

func processMessage(ch *amqp.Channel, msg amqp.Delivery) {
	var m emailMessage
	if err := json.Unmarshal(msg.Body, &m); err != nil {
		log.Printf("[consumer] Failed to parse message: %v", err)
		_ = msg.Nack(false, false)
		return
	}

	log.Printf("[consumer] Received %s", m.EventType)

	if err := dispatch(m); err != nil {
		log.Printf("[consumer] Failed to process %s: %v", m.EventType, err)
		_ = msg.Nack(false, false)
		return
	}

	_ = msg.Ack(false)
}

func dispatch(m emailMessage) error {
	switch m.EventType {
	case "email.password_reset":
		var payload handlers.PasswordResetPayload
		if err := json.Unmarshal(m.Payload, &payload); err != nil {
			return fmt.Errorf("unmarshal payload: %w", err)
		}
		return handlers.HandlePasswordReset(payload)
	case "email.verification":
		var payload handlers.EmailVerificationPayload
		if err := json.Unmarshal(m.Payload, &payload); err != nil {
			return fmt.Errorf("unmarshal payload: %w", err)
		}
		return handlers.HandleEmailVerification(payload)
	default:
		log.Printf("[consumer] Unhandled event_type: %s", m.EventType)
		return nil
	}
}

func getenv(key, fallback string) string {
	if v := os.Getenv(key); v != "" {
		return v
	}
	return fallback
}

